//! P4 certified metadata CRDT — provable knowledge only, merged by the carve-lattice meet.
//!
//! A scene's certified knowledge is a SET of discrete admitted predicates (object exists, is at
//! rest, has genus g, occupies quantised cell (qx,qy), moves in octant d). Only predicates whose
//! physics verdict is `Accept` enter the set.
//!
//! The CRDT join across replicas/observers is the **meet** (set intersection) — the confluent
//! silhouette-carve proven in `gnosis-math/Gnosis/SilhouetteCarveLattice.lean:79`
//! (`meet_is_semilattice`, `carve_append`): idempotent, commutative, associative. Only knowledge
//! that *both* observers certify survives a merge — conservative and conflict-free, converging
//! with a proof. We deliberately do NOT use k-of-N consensus: `consensus_not_idempotent` (line 154)
//! proves threshold voting is not a lattice (a duplicated vote changes the result), so it cannot be
//! the join. The K-frame anti-flicker in the tracker is a *local pre-filter*, not this join.

use crate::physics::{AdmittedState, Verdict};
use crate::scene::SceneObject;
use std::collections::{BTreeMap, BTreeSet};

/// Quantisation grid for positional predicates.
pub const QGRID: i32 = 16;

/// A discrete, admitted fact about the scene. Ordered so it lives in a BTreeSet.
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
pub enum Predicate {
    /// Object `id` exists and is certified-known.
    Exists(u64),
    /// Object `id` is at rest.
    AtRest(u64),
    /// Object `id` has genus `g`.
    Genus(u64, u32),
    /// Object `id` occupies quantised cell (qx, qy) in [0,QGRID).
    Cell(u64, i32, i32),
    /// Object `id` moves in octant `oct` in [0,8).
    MovingOctant(u64, u8),
    /// AGENCY (Phase 2): Thoth's hand `hand_id` could GRASP object `obj` — a certified-admissible
    /// grasp affordance (regime stable, abstain_reason clean, size within reach, impulse arrestable),
    /// gated under `fork_preserves_charge` (a grasp arrests the conserved momentum via contact).
    /// Scoped (via `obj_id`) to the GRABBABLE object, so it survives only while that object keeps
    /// re-certifying as graspable.
    PossibleGrab(u64, u64),
    /// AGENCY (Phase 2): the certified COUNTERFACTUAL outcome for object `obj` — IF a (here-implicit)
    /// admissible impulse were applied, the post-impulse velocity quantises to (vx_q, vy_q) and the
    /// hypothetical collision is momentum-conserved + subluminal. Quantized so it lives in the discrete
    /// CRDT set and merges by the carve-meet (two observers agree on the same quantized outcome).
    /// Gated under `fork_preserves_charge` (v' = (p+J)/m) + `subluminal_never_reaches_front` (causal).
    CertifiedOutcome(u64, i32, i32),
}

impl Predicate {
    /// The object id this predicate is about. Every variant is keyed by an object id; the scoped
    /// accumulation in `SceneModel::accumulate` uses this to decide WHICH predicates participate in
    /// the carve-meet (observed objects) vs. carry forward untouched (unobserved objects).
    pub fn obj_id(&self) -> u64 {
        match self {
            Predicate::Exists(id)
            | Predicate::AtRest(id)
            | Predicate::Genus(id, _)
            | Predicate::Cell(id, _, _)
            | Predicate::MovingOctant(id, _) => *id,
            // Agency predicates are scoped to the OBJECT they are about (the grabbable / acted-on
            // object), so they accumulate + carve-meet with that object's observation — a possible-grab
            // survives only while the object keeps re-certifying as graspable, and is carved away when
            // it stops (e.g. the object starts moving and is no longer arrestable).
            Predicate::PossibleGrab(_, obj) | Predicate::CertifiedOutcome(obj, _, _) => *obj,
        }
    }
}

/// A set of certified predicates plus the law each was admitted under.
#[derive(Debug, Clone, Default)]
pub struct CertifiedKnowledge {
    pub admitted: BTreeSet<Predicate>,
    pub provenance: BTreeMap<Predicate, &'static str>,
}

impl CertifiedKnowledge {
    pub fn new() -> Self {
        Self::default()
    }

    fn add(&mut self, p: Predicate, law: &'static str) {
        self.provenance.insert(p.clone(), law);
        self.admitted.insert(p);
    }

    /// Public insert of a certified, law-tagged predicate — used by `SceneModel` to inject the Phase 2
    /// AGENCY predicates (`PossibleGrab` / `CertifiedOutcome`) into the per-tick certified set so they
    /// accumulate + publish alongside the perceptual predicates. Same discipline as `add`: every
    /// predicate carries the green law it was admitted under.
    pub fn add_public(&mut self, p: Predicate, law: &'static str) {
        self.add(p, law);
    }

    /// Quantize a relative velocity component into the discrete CRDT grid (so a `CertifiedOutcome`
    /// predicate lives in the BTreeSet and two observers converge on the same cell). Maps the causal
    /// velocity range [-1,1] onto the `QGRID` resolution used by positional cells.
    pub fn quantize_velocity(v: f32) -> i32 {
        (v.clamp(-1.0, 1.0) * QGRID as f32).round() as i32
    }

    /// Build the local certified knowledge from admitted scene objects. Only `Accept` facts enter.
    pub fn from_scene(objects: &[(SceneObject, AdmittedState)]) -> Self {
        let mut k = CertifiedKnowledge::new();
        for (obj, adm) in objects {
            if adm.verdict == Verdict::Decline {
                continue; // declined object contributes nothing
            }
            // Existence requires Accept on exists_known.
            let exists_ok = adm
                .facts
                .iter()
                .any(|f| f.fact == "exists_known" && f.verdict == Verdict::Accept);
            if !exists_ok {
                continue; // abstain on existence -> nothing certified for this object
            }
            k.add(
                Predicate::Exists(obj.id),
                "InformationConservation.information_conservation",
            );
            k.add(
                Predicate::Genus(obj.id, obj.genus),
                "SilhouetteCarveLattice.meet_is_semilattice",
            );
            // Quantised cell from normalised position (clamp into grid).
            let qx = ((obj.x * QGRID as f32).floor() as i32).clamp(0, QGRID - 1);
            let qy = ((obj.y * QGRID as f32).floor() as i32).clamp(0, QGRID - 1);
            k.add(
                Predicate::Cell(obj.id, qx, qy),
                "AckermannLightConeBridge.certified_iff_in_lightcone",
            );
            // Motion: at rest, or moving in an octant (only if velocity was accepted).
            if adm.at_rest {
                k.add(
                    Predicate::AtRest(obj.id),
                    "VacuumIsOnlyForce.vacuum_force_contracts",
                );
            } else {
                let vel_ok = adm
                    .facts
                    .iter()
                    .any(|f| f.fact == "velocity_causal" && f.verdict == Verdict::Accept);
                if vel_ok && (obj.vx.abs() > 1e-4 || obj.vy.abs() > 1e-4) {
                    let ang = obj.vy.atan2(obj.vx); // [-pi,pi]
                    let oct = (((ang / std::f32::consts::PI) * 4.0).round() as i32).rem_euclid(8) as u8;
                    k.add(
                        Predicate::MovingOctant(obj.id, oct),
                        "AckermannLightConeBridge.subluminal_never_reaches_front",
                    );
                }
            }
        }
        k
    }

    /// The certified CRDT join: the carve meet (intersection). Idempotent, commutative,
    /// associative — `SilhouetteCarveLattice.meet_is_semilattice`. Only mutually-certified
    /// knowledge survives. Provenance keeps either side's law (same predicate ⇒ same law class).
    pub fn meet(&self, other: &CertifiedKnowledge) -> CertifiedKnowledge {
        let admitted: BTreeSet<Predicate> = self
            .admitted
            .intersection(&other.admitted)
            .cloned()
            .collect();
        let mut provenance = BTreeMap::new();
        for p in &admitted {
            if let Some(l) = self.provenance.get(p).or_else(|| other.provenance.get(p)) {
                provenance.insert(p.clone(), *l);
            }
        }
        CertifiedKnowledge {
            admitted,
            provenance,
        }
    }

    /// Scoped accumulation step — the running-picture memory join (Phase 3a). The certified picture
    /// ACCUMULATES across ticks instead of being rebuilt ephemerally each frame. A blind GLOBAL
    /// `meet` would erode legitimately-changing facts (a moving object re-quantises into a different
    /// `Cell`/`MovingOctant` each tick, so an unscoped intersection would delete it). So the
    /// accumulation is SCOPED by observation, keyed by object id:
    ///
    ///   * For objects OBSERVED this tick (`observed_ids`): their accumulated facts carve-MEET against
    ///     this tick's certified facts for the SAME object — a fact survives only while it keeps
    ///     re-certifying. This is the existing carve intersection (`meet`), restricted to one object's
    ///     predicates. Conservative, anti-flicker, idempotent under re-observation
    ///     (`SilhouetteCarveLattice.meet_is_semilattice` / `carve_dup`). NEW facts for an observed
    ///     object (e.g. a freshly-certified object's predicates) JOIN the running set, because there
    ///     is no prior accumulated fact to intersect them away — monotone growth on first sight.
    ///   * For objects NOT observed this tick (occluded / out of frame): their accumulated facts
    ///     CARRY FORWARD untouched — "known until contradicted", never deleted. This is the honest
    ///     permanence tied to metacog C2: a carried-forward shadow whose re-certification lapses must
    ///     drop to abstain on a *later* observation, never be silently dropped here.
    ///
    /// This reuses the carve `meet` (no union, no k-of-N, no new lattice op); the discipline lives in
    /// WHICH predicates participate, not in a new operator.
    ///
    /// Per-object carve-meet detail: for an observed object, a prior accumulated predicate survives iff
    /// it is also certified this tick (set intersection over that object's predicates). A this-tick
    /// predicate with no prior accumulated counterpart for that object is admitted (first-sight join).
    pub fn accumulate(
        &mut self,
        this_tick: &CertifiedKnowledge,
        observed_ids: &BTreeSet<u64>,
    ) {
        let mut next = CertifiedKnowledge::new();

        // (1) Carried-forward facts for UNOBSERVED objects: keep accumulated predicates untouched.
        for p in &self.admitted {
            if !observed_ids.contains(&p.obj_id()) {
                let law = self.provenance.get(p).copied().unwrap_or("carried_forward");
                next.add(p.clone(), law);
            }
        }

        // (2) OBSERVED objects: carve-meet prior-accumulated against this tick, PER object. The meet
        //     (set intersection) of {prior accumulated facts for this object} with {this-tick facts}
        //     keeps exactly the re-certified facts. Equivalently, since a prior fact survives iff it
        //     re-certifies (∈ this_tick) and a this-tick fact with no prior counterpart joins on first
        //     sight, the surviving set for an observed object is precisely this tick's certified facts
        //     for that object: a fact that stopped re-certifying is dropped (carve contradiction); a
        //     freshly-certified fact joins (monotone growth on first sight). No union, no k-of-N.
        for p in &this_tick.admitted {
            if observed_ids.contains(&p.obj_id()) {
                let law = this_tick.provenance.get(p).copied().unwrap_or("certified");
                next.add(p.clone(), law);
            }
        }

        *self = next;
    }

    pub fn len(&self) -> usize {
        self.admitted.len()
    }
    pub fn is_empty(&self) -> bool {
        self.admitted.is_empty()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn k(preds: &[Predicate]) -> CertifiedKnowledge {
        let mut k = CertifiedKnowledge::new();
        for p in preds {
            k.add(p.clone(), "test");
        }
        k
    }

    #[test]
    fn meet_is_idempotent() {
        let a = k(&[Predicate::Exists(1), Predicate::AtRest(1), Predicate::Genus(2, 1)]);
        assert_eq!(a.meet(&a).admitted, a.admitted);
    }

    #[test]
    fn meet_is_commutative() {
        let a = k(&[Predicate::Exists(1), Predicate::Genus(1, 0)]);
        let b = k(&[Predicate::Exists(1), Predicate::Genus(1, 1)]);
        assert_eq!(a.meet(&b).admitted, b.meet(&a).admitted);
    }

    #[test]
    fn meet_is_associative() {
        let a = k(&[Predicate::Exists(1), Predicate::Exists(2), Predicate::AtRest(1)]);
        let b = k(&[Predicate::Exists(1), Predicate::Exists(2)]);
        let c = k(&[Predicate::Exists(2), Predicate::AtRest(1)]);
        let ab_c = a.meet(&b).meet(&c);
        let a_bc = a.meet(&b.meet(&c));
        assert_eq!(ab_c.admitted, a_bc.admitted);
    }

    #[test]
    fn meet_is_intersection_not_consensus() {
        // Duplicating a replica must not change the result (idempotence) — the property that
        // k-of-N consensus violates (consensus_not_idempotent).
        let a = k(&[Predicate::Exists(1)]);
        let b = k(&[Predicate::Exists(1), Predicate::Exists(2)]);
        let once = a.meet(&b);
        let twice = a.meet(&b).meet(&b);
        assert_eq!(once.admitted, twice.admitted);
        assert!(once.admitted.contains(&Predicate::Exists(1)));
        assert!(!once.admitted.contains(&Predicate::Exists(2))); // only mutually-certified survives
    }

    // ── Phase 3a: scoped running-picture accumulation (the memory foundation) ───────────────────
    // `accumulate` reuses the carve `meet` (intersection) discipline — observed objects' facts
    // survive only while re-certifying (anti-flicker, idempotent: `carve_dup` /
    // `meet_is_semilattice`), unobserved objects' facts carry forward untouched ("known until
    // contradicted"). It is NOT a union and NOT k-of-N (`consensus_not_idempotent`).

    fn ids(xs: &[u64]) -> BTreeSet<u64> {
        xs.iter().copied().collect()
    }

    #[test]
    fn accumulate_idempotent_under_re_observation() {
        // Re-feeding the SAME tick for the SAME observed object changes nothing — the carve-meet of a
        // re-certified fact with itself is itself (`meet_is_semilattice` idempotence / `carve_dup`).
        let tick = k(&[
            Predicate::Exists(1),
            Predicate::AtRest(1),
            Predicate::Genus(1, 0),
            Predicate::Cell(1, 3, 4),
        ]);
        let mut acc = CertifiedKnowledge::new();
        acc.accumulate(&tick, &ids(&[1]));
        let after_first = acc.admitted.clone();
        // Feed the identical tick again.
        acc.accumulate(&tick, &ids(&[1]));
        assert_eq!(acc.admitted, after_first, "re-observation is idempotent");
        assert_eq!(acc.admitted, tick.admitted);
    }

    #[test]
    fn accumulate_conservative_on_contradiction() {
        // A fact that STOPS re-certifying for an OBSERVED object drops out via the carve-meet
        // (intersection contradiction) — conservative, not retained on faith. Here object 1 was
        // at_rest, then is observed again WITHOUT the at_rest fact (it started moving): AtRest(1) is
        // carved away, while its still-re-certified facts survive and the new motion fact joins.
        let t0 = k(&[Predicate::Exists(1), Predicate::AtRest(1), Predicate::Genus(1, 0)]);
        let mut acc = CertifiedKnowledge::new();
        acc.accumulate(&t0, &ids(&[1]));
        assert!(acc.admitted.contains(&Predicate::AtRest(1)));

        let t1 = k(&[
            Predicate::Exists(1),
            Predicate::Genus(1, 0),
            Predicate::MovingOctant(1, 2),
        ]);
        acc.accumulate(&t1, &ids(&[1]));
        assert!(
            !acc.admitted.contains(&Predicate::AtRest(1)),
            "stopped re-certifying => carved out (conservative)"
        );
        assert!(acc.admitted.contains(&Predicate::Exists(1)));
        assert!(acc.admitted.contains(&Predicate::Genus(1, 0)));
        assert!(acc.admitted.contains(&Predicate::MovingOctant(1, 2)));
    }

    #[test]
    fn accumulate_carries_forward_unobserved() {
        // An object that LEAVES FRAME (not observed this tick) keeps its accumulated facts untouched —
        // "known until contradicted", never silently deleted (the metacog-C2 honest-permanence tie).
        let t0 = k(&[
            Predicate::Exists(7),
            Predicate::AtRest(7),
            Predicate::Genus(7, 1),
        ]);
        let mut acc = CertifiedKnowledge::new();
        acc.accumulate(&t0, &ids(&[7]));

        // Next tick: object 7 is occluded (not in observed_ids), and a DIFFERENT object 9 is observed.
        let t1 = k(&[Predicate::Exists(9), Predicate::AtRest(9)]);
        acc.accumulate(&t1, &ids(&[9]));

        // Object 7's facts carried forward untouched...
        assert!(acc.admitted.contains(&Predicate::Exists(7)));
        assert!(acc.admitted.contains(&Predicate::AtRest(7)));
        assert!(acc.admitted.contains(&Predicate::Genus(7, 1)));
        // ...while object 9's facts joined.
        assert!(acc.admitted.contains(&Predicate::Exists(9)));
        assert!(acc.admitted.contains(&Predicate::AtRest(9)));
    }

    // ── Phase 2: AGENCY predicates (PossibleGrab / CertifiedOutcome) accumulate + meet ──────────

    #[test]
    fn possible_grab_accumulates_and_meets() {
        // A PossibleGrab(hand=99, obj=1) is scoped (via obj_id) to object 1, so it accumulates while
        // object 1 keeps re-certifying as graspable, carve-MEETS idempotently, and survives a meet with
        // another observer that ALSO certifies the same grab (only mutually-certified knowledge does).
        let grab = Predicate::PossibleGrab(99, 1);
        let outcome = Predicate::CertifiedOutcome(1, 1, 0);
        assert_eq!(grab.obj_id(), 1, "grab is scoped to the grabbable object");
        assert_eq!(outcome.obj_id(), 1, "outcome is scoped to the acted-on object");

        let t0 = k(&[Predicate::Exists(1), grab.clone(), outcome.clone()]);
        let mut acc = CertifiedKnowledge::new();
        acc.accumulate(&t0, &ids(&[1]));
        assert!(acc.admitted.contains(&grab), "grab joins on first sight");
        assert!(acc.admitted.contains(&outcome), "outcome joins on first sight");

        // Re-observe object 1 still graspable => idempotent (carve_dup / meet_is_semilattice).
        acc.accumulate(&t0, &ids(&[1]));
        assert!(acc.admitted.contains(&grab), "re-certified grab is idempotent");

        // Object 1 observed again but NO LONGER graspable (it started moving) => grab carved away.
        let t1 = k(&[Predicate::Exists(1), Predicate::MovingOctant(1, 2)]);
        acc.accumulate(&t1, &ids(&[1]));
        assert!(!acc.admitted.contains(&grab), "stopped certifying graspable => carved out (conservative)");

        // CRDT meet: two observers that BOTH certify the grab keep it; an observer that does not, drops it.
        let a = k(&[Predicate::Exists(1), grab.clone()]);
        let b = k(&[Predicate::Exists(1), grab.clone()]);
        let c = k(&[Predicate::Exists(1)]);
        assert!(a.meet(&b).admitted.contains(&grab), "mutually-certified grab survives the meet");
        assert!(!a.meet(&c).admitted.contains(&grab), "only mutually-certified survives");
    }

    #[test]
    fn accumulate_monotone_growth_for_new_objects() {
        // A newly-certified object's facts JOIN the running set on first sight (monotone growth) —
        // there is no prior accumulated counterpart to intersect them away. This is the first-sight
        // side of the scoped carve-meet, NOT a global union (a global meet would have erased them).
        let t0 = k(&[Predicate::Exists(1), Predicate::AtRest(1)]);
        let mut acc = CertifiedKnowledge::new();
        acc.accumulate(&t0, &ids(&[1]));
        let before = acc.len();

        // Object 2 appears for the first time AND object 1 is still observed.
        let t1 = k(&[
            Predicate::Exists(1),
            Predicate::AtRest(1),
            Predicate::Exists(2),
            Predicate::Genus(2, 0),
        ]);
        acc.accumulate(&t1, &ids(&[1, 2]));
        assert!(acc.admitted.contains(&Predicate::Exists(2)));
        assert!(acc.admitted.contains(&Predicate::Genus(2, 0)));
        assert!(acc.admitted.contains(&Predicate::Exists(1))); // existing object retained
        assert!(acc.len() > before, "running set grew with the new object");
    }
}
